#include<bits/stdc++.h>using namespace std;int main() {    ios::sync_with_stdio(0); cin.tie(0);    int t;    cin>>t;    while(t--) {        int n, q;        cin>>n>>q;        vector<int> a(n);        for(int& num:a)            cin>>num;        vector<int> x(q);        for(int& num:x)             cin>>num;        int prev=31;        for(const int xi:x) {            if(xi>=prev) continue;            prev=xi;            for(int& aj:a) {                if(aj%(1<<xi)==0)                    aj+=(1<<(xi-1));            }        }        for(int aj:a)            cout<<aj<<" ";        cout<<endl;    }    return 0;}